import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Deceptive Security",
  subtitle: "Advanced honeypots, honeytokens, and deception technology",
  description: "Turn the tables on attackers with our deceptive security platform. Deploy intelligent honeypots, breadcrumbs, and lures that detect intruders early and gather intelligence on attack techniques. Deception technology provides early warning with zero false positives.",
  benefits: [
    "Intelligent honeypot deployment across your infrastructure",
    "Early intruder detection before damage occurs",
    "Attack technique intelligence gathering",
    "Dynamic deception environments that adapt to threats",
    "Zero false positives - any alert is a real threat"
  ],
  features: [
    { title: "Honeypot Networks", description: "Deploy realistic decoy systems and services" },
    { title: "Honeytokens", description: "Create fake credentials and data that trigger alerts" },
    { title: "Breadcrumbs", description: "Place deceptive hints to lure attackers" },
    { title: "Attack Analytics", description: "Learn attacker techniques and TTPs" },
    { title: "Dynamic Deception", description: "Automatically adapt decoys based on environment" }
  ],
  howItWorks: [
    { title: "Decoy Deployment", description: "Honeypots and honeytokens are deployed across the network" },
    { title: "Attacker Engagement", description: "When attackers interact with decoys, they're detected" },
    { title: "Intelligence Gathering", description: "Information about attacker tools and techniques is collected" },
    { title: "Early Warning", description: "Security team is alerted before real assets are compromised" }
  ],
  color: "#dc2626",
  icon: "M15 12a3 3 0 11-6 0 3 3 0 016 0z M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z",
  gradient: "from-red-600 to-pink-600"
};

function DeceptiveSecurity() {
  return <FeatureDetail {...pageData} />;
}

export default DeceptiveSecurity;
